# Sentiment analysis with structured output (Anthropic)
import anthropic

client = anthropic.Anthropic()

sentiment_schema = {
    "type": "object",
    "properties": {
        "sentiment": {
            "type": "string",
            "enum": ["positive", "negative", "neutral"],
            "description": "Overall sentiment of the text"
        },
        "confidence": {
            "type": "number",
            "minimum": 0.0,
            "maximum": 1.0,
            "description": "Confidence score between 0 and 1"
        },
        "key_phrases": {
            "type": "array",
            "items": {"type": "string"},
            "description": "Up to five phrases driving the sentiment"
        },
        "explanation": {
            "type": "string",
            "description": "One-sentence rationale for the classification"
        }
    },
    "required": ["sentiment", "confidence", "key_phrases", "explanation"]
}

response = client.messages.create(
    model="claude-opus-4-5",
    max_tokens=512,
    tools=[{
        "name": "analyze_sentiment",
        "description": "Analyze the sentiment of the provided text.",
        "input_schema": sentiment_schema
    }],
    # Force the model to call this exact tool; it cannot emit free text
    tool_choice={"type": "tool", "name": "analyze_sentiment"},
    messages=[{
        "role": "user",
        "content": (
            "Analyze: 'Delivery was two days late and the packaging was damaged, "
            "but the product itself exceeded every expectation I had.'"
        )
    }]
)

# When tool_choice forces a specific tool, content[0] is always a tool_use block
result = response.content[0].input
print(f"Sentiment  : {result['sentiment']}")
print(f"Confidence : {result['confidence']:.0%}")
print(f"Key phrases: {', '.join(result['key_phrases'])}")
print(f"Explanation: {result['explanation']}")
# => Sentiment  : neutral
# => Confidence : 72%
# => Key phrases: late delivery, damaged packaging, exceeded expectations
# => Explanation: Mixed signals — logistics failure offset by product quality.

import anthropic
client = anthropic.Anthropic()

# ---- WRONG: every field optional, no enum, blind attribute access ----
def extract_order_bad(text: str) -> dict:
    resp = client.messages.create(
        model="claude-opus-4-5",
        max_tokens=256,
        tools=[{
            "name": "extract",
            "description": "Extract data",
            "input_schema": {
                "type": "object",
                "properties": {
                    # Optional everywhere — model may omit critical values
                    "status": {"type": "string"},     # No enum: model invents values like "in-transit"
                    "count":  {"type": "number"},     # No min/max guard
                }
                # Missing "required" — all fields optional by default
            }
        }],
        messages=[{"role": "user", "content": text}]
    )
    # Blindly accessing .input without checking stop_reason or block type
    # Crashes with AttributeError if stop_reason is "end_turn" (no tool call)
    return resp.content[0].input   # BUG: may raise AttributeError


# ---- CORRECT: required fields, enum, validated access, forced tool call ----
def extract_order_good(text: str) -> dict:
    resp = client.messages.create(
        model="claude-opus-4-5",
        max_tokens=256,
        tools=[{
            "name": "extract_order",
            "description": "Extract order status and item count from the text.",
            "input_schema": {
                "type": "object",
                "properties": {
                    "status": {
                        "type": "string",
                        "enum": ["pending", "shipped", "delivered", "cancelled"],
                        "description": "Current order status, exactly one of the listed values"
                    },
                    "item_count": {
                        "type": "integer",
                        "minimum": 0,
                        "description": "Number of distinct items in the order"
                    },
                },
                "required": ["status", "item_count"]    # Both always present
            }
        }],
        # Force the model to call this tool — no free-text fallback
        tool_choice={"type": "tool", "name": "extract_order"},
        messages=[{"role": "user", "content": text}]
    )
    # Defensive access: check type before using
    block = resp.content[0]
    if block.type != "tool_use":
        raise RuntimeError(f"Expected tool_use block, got {block.type!r}")
    return block.input
